BEGIN; CREATE TABLE IF NOT EXISTS backup_charter_payments_2012_2015_mediumcue_match_20260419 (LIKE charter_payments INCLUDING ALL); DROP TABLE IF EXISTS tmp_medium_rows; CREATE TEMP TABLE tmp_medium_rows AS WITH cp_scope AS (SELECT cp.id AS cp_id, cp.amount, cp.payment_date::date AS payment_date, lower(coalesce(cp.payment_method,'')) AS pm, lower(coalesce(cp.source,'')) AS src, lower(coalesce(cp.payment_key,'')) AS pkey FROM charter_payments cp WHERE cp.banking_transaction_id IS NULL AND cp.payment_date::date BETWEEN DATE '2012-01-01' AND DATE '2015-12-31' AND cp.amount > 0 AND lower(coalesce(cp.payment_method,'')) IN ('credit_card','bank_transfer','check','cheque','chq') AND NOT (lower(coalesce(cp.source,'')) LIKE '%square%' OR lower(coalesce(cp.source,'')) LIKE '%sq %' OR lower(coalesce(cp.source,'')) LIKE '%sq*%' OR lower(coalesce(cp.source,'')) LIKE '%global system%' OR lower(coalesce(cp.source,'')) LIKE '%global payments%' OR lower(coalesce(cp.source,'')) LIKE '%mcard%' OR lower(coalesce(cp.source,'')) LIKE '%vcard%' OR lower(coalesce(cp.source,'')) LIKE '%acard%' OR lower(coalesce(cp.source,'')) LIKE '%dcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%square%' OR lower(coalesce(cp.payment_method,'')) LIKE '%sq %' OR lower(coalesce(cp.payment_method,'')) LIKE '%sq*%' OR lower(coalesce(cp.payment_method,'')) LIKE '%global system%' OR lower(coalesce(cp.payment_method,'')) LIKE '%global payments%' OR lower(coalesce(cp.payment_method,'')) LIKE '%mcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%vcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%acard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%dcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%square%' OR lower(coalesce(cp.payment_key,'')) LIKE '%sq %' OR lower(coalesce(cp.payment_key,'')) LIKE '%sq*%' OR lower(coalesce(cp.payment_key,'')) LIKE '%global system%' OR lower(coalesce(cp.payment_key,'')) LIKE '%global payments%' OR lower(coalesce(cp.payment_key,'')) LIKE '%mcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%vcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%acard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%dcard%')), candidates AS (SELECT cp.cp_id, bt.id AS bt_id, abs(cp.amount - bt.credit_amount) AS amt_diff, abs((bt.transaction_date::date - cp.payment_date::date)) AS date_diff_days, lower(coalesce(bt.description,'')) AS bdesc, cp.pm, cp.src, cp.pkey FROM cp_scope cp JOIN banking_transactions bt ON abs(cp.amount - bt.credit_amount) <= 0.01 AND bt.transaction_date::date BETWEEN cp.payment_date::date - INTERVAL '14 day' AND cp.payment_date::date + INTERVAL '14 day' WHERE NOT (lower(coalesce(bt.description,'')) LIKE '%square%' OR lower(coalesce(bt.description,'')) LIKE '%sq %' OR lower(coalesce(bt.description,'')) LIKE '%sq*%' OR lower(coalesce(bt.description,'')) LIKE '%global system%' OR lower(coalesce(bt.description,'')) LIKE '%global payments%' OR lower(coalesce(bt.description,'')) LIKE '%mcard%' OR lower(coalesce(bt.description,'')) LIKE '%vcard%' OR lower(coalesce(bt.description,'')) LIKE '%acard%' OR lower(coalesce(bt.description,'')) LIKE '%dcard%')), scored AS (SELECT c.cp_id, c.bt_id, c.date_diff_days, CASE WHEN ((c.pm IN ('check','cheque','chq') AND (c.src ~ '(check|cheque|chk)' OR c.pkey ~ '(check|cheque|chk)' OR c.bdesc ~ '(check|cheque|chk)')) OR (c.pm = 'bank_transfer' AND (c.src ~ '(transfer|wire|e-?transfer|deposit)' OR c.pkey ~ '(transfer|wire|e-?transfer|deposit)' OR c.bdesc ~ '(transfer|wire|e-?transfer|deposit)')) OR (c.pm = 'credit_card' AND (c.src ~ '(visa|master|card|credit|pos|merchant)' OR c.pkey ~ '(visa|master|card|credit|pos|merchant)' OR c.bdesc ~ '(visa|master|card|credit|pos|merchant)'))) THEN 'HIGH' WHEN c.date_diff_days <= 2 THEN 'MEDIUM' ELSE 'LOW' END AS cue_level FROM candidates c), exactly_one AS (SELECT cp_id, MIN(bt_id) AS bt_id FROM scored GROUP BY cp_id HAVING COUNT(*) = 1) SELECT s.cp_id, s.bt_id FROM scored s JOIN exactly_one eo ON eo.cp_id = s.cp_id AND eo.bt_id = s.bt_id WHERE s.cue_level = 'MEDIUM'; SELECT COUNT(*) AS rows_to_update FROM tmp_medium_rows; INSERT INTO backup_charter_payments_2012_2015_mediumcue_match_20260419 SELECT cp.* FROM charter_payments cp JOIN tmp_medium_rows t ON t.cp_id = cp.id ON CONFLICT (id) DO NOTHING; WITH updated AS (UPDATE charter_payments cp SET banking_transaction_id = t.bt_id FROM tmp_medium_rows t WHERE cp.id = t.cp_id AND cp.banking_transaction_id IS NULL RETURNING cp.id) SELECT COUNT(*) AS rows_updated FROM updated; WITH cp_scope AS (SELECT cp.id, cp.amount, cp.payment_date::date AS payment_date, lower(coalesce(cp.payment_method,'')) AS pm, lower(coalesce(cp.source,'')) AS src, lower(coalesce(cp.payment_key,'')) AS pkey FROM charter_payments cp WHERE cp.banking_transaction_id IS NULL AND cp.payment_date::date BETWEEN DATE '2012-01-01' AND DATE '2015-12-31' AND cp.amount > 0 AND lower(coalesce(cp.payment_method,'')) IN ('credit_card','bank_transfer','check','cheque','chq') AND NOT (lower(coalesce(cp.source,'')) LIKE '%square%' OR lower(coalesce(cp.source,'')) LIKE '%sq %' OR lower(coalesce(cp.source,'')) LIKE '%sq*%' OR lower(coalesce(cp.source,'')) LIKE '%global system%' OR lower(coalesce(cp.source,'')) LIKE '%global payments%' OR lower(coalesce(cp.source,'')) LIKE '%mcard%' OR lower(coalesce(cp.source,'')) LIKE '%vcard%' OR lower(coalesce(cp.source,'')) LIKE '%acard%' OR lower(coalesce(cp.source,'')) LIKE '%dcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%square%' OR lower(coalesce(cp.payment_method,'')) LIKE '%sq %' OR lower(coalesce(cp.payment_method,'')) LIKE '%sq*%' OR lower(coalesce(cp.payment_method,'')) LIKE '%global system%' OR lower(coalesce(cp.payment_method,'')) LIKE '%global payments%' OR lower(coalesce(cp.payment_method,'')) LIKE '%mcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%vcard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%acard%' OR lower(coalesce(cp.payment_method,'')) LIKE '%dcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%square%' OR lower(coalesce(cp.payment_key,'')) LIKE '%sq %' OR lower(coalesce(cp.payment_key,'')) LIKE '%sq*%' OR lower(coalesce(cp.payment_key,'')) LIKE '%global system%' OR lower(coalesce(cp.payment_key,'')) LIKE '%global payments%' OR lower(coalesce(cp.payment_key,'')) LIKE '%mcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%vcard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%acard%' OR lower(coalesce(cp.payment_key,'')) LIKE '%dcard%')), candidates AS (SELECT cp.id AS cp_id, bt.id AS bt_id FROM cp_scope cp JOIN banking_transactions bt ON abs(cp.amount - bt.credit_amount) <= 0.01 AND bt.transaction_date::date BETWEEN cp.payment_date::date - INTERVAL '14 day' AND cp.payment_date::date + INTERVAL '14 day' WHERE NOT (lower(coalesce(bt.description,'')) LIKE '%square%' OR lower(coalesce(bt.description,'')) LIKE '%sq %' OR lower(coalesce(bt.description,'')) LIKE '%sq*%' OR lower(coalesce(bt.description,'')) LIKE '%global system%' OR lower(coalesce(bt.description,'')) LIKE '%global payments%' OR lower(coalesce(bt.description,'')) LIKE '%mcard%' OR lower(coalesce(bt.description,'')) LIKE '%vcard%' OR lower(coalesce(bt.description,'')) LIKE '%acard%' OR lower(coalesce(bt.description,'')) LIKE '%dcard%')), one_candidate AS (SELECT cp_id FROM candidates GROUP BY cp_id HAVING COUNT(*) = 1) SELECT (SELECT COUNT(*) FROM cp_scope) AS remaining_unmatched_total, (SELECT COUNT(*) FROM one_candidate) AS remaining_exactly_one_candidate_rows; SELECT cp.id, cp.amount, cp.payment_date, cp.payment_method, cp.source, cp.banking_transaction_id, bt.transaction_date, bt.description FROM charter_payments cp JOIN tmp_medium_rows t ON t.cp_id = cp.id JOIN banking_transactions bt ON bt.id = cp.banking_transaction_id ORDER BY cp.id LIMIT 25; COMMIT;